import{_ as a,o as r,c as t,ae as o}from"./chunks/framework.B6gjLfeO.js";const k=JSON.parse('{"title":"Branch Slack App","description":"","frontmatter":{"title":"Branch Slack App","slug":"branch-slack-app"},"headers":[],"relativePath":"marketer-hub/branch-slack-app.md","filePath":"marketer-hub/branch-slack-app.md"}'),n={name:"marketer-hub/branch-slack-app.md"};function i(l,e,c,h,s,u){return r(),t("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Use the Branch Slack App to quickly and easily generate Branch Links within your Slack workspace. As with all Branch Links created, you&#39;ll have the power to deep link users to your mobile app while gaining valuable measurement on your link performance through the Branch Dashboard.</p><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><p>To start using the Branch Slack App, you must:</p><ol><li>Create a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a> and obtain your <strong>Branch Key</strong> from your <a href="https://dashboard.branch.io/account-settings/profile" target="_blank" rel="noreferrer">Account Settings</a>.</li><li>Have a <a href="https://slack.com/get-started#/createnew" target="_blank" rel="noreferrer">Slack workspace</a>.</li></ol><h2 id="creating-links-with-the-branch-slack-app" tabindex="-1">Creating links with the Branch Slack App <a class="header-anchor" href="#creating-links-with-the-branch-slack-app" aria-label="Permalink to &quot;Creating links with the Branch Slack App&quot;">​</a></h2><h3 id="step-1-add-the-branch-to-your-slack-workspace" tabindex="-1">Step 1: Add the Branch to your Slack Workspace <a class="header-anchor" href="#step-1-add-the-branch-to-your-slack-workspace" aria-label="Permalink to &quot;Step 1: Add the Branch to your Slack Workspace&quot;">​</a></h3><p>Add Branch to your Slack workspace by going to <a href="https://branch.link/slack" target="_blank" rel="noreferrer">branch.link/slack</a>.</p><h3 id="_2-configure-the-slack-app-with-your-branch-credentials" tabindex="-1">2. Configure the Slack App with your Branch credentials <a class="header-anchor" href="#_2-configure-the-slack-app-with-your-branch-credentials" aria-label="Permalink to &quot;2. Configure the Slack App with your Branch credentials&quot;">​</a></h3><p>Once you’ve added the Branch Slack App to your workspace, you must add the <strong>Branch Key</strong> obtained from the <a href="./branch-slack-app.html#prerequisites">&quot;Before you begin&quot; step</a> of this article.</p><p>.gif &quot;Enter Branch Key.gif&quot;)</p><h3 id="_3-create-your-link" tabindex="-1">3. Create your link <a class="header-anchor" href="#_3-create-your-link" aria-label="Permalink to &quot;3. Create your link&quot;">​</a></h3><p>You can now create links using the <code>/link</code> command. Here you&#39;ll be able to set specific configurations for your Branch Link like <strong>Analytics Tags</strong> and <strong>Deeplink Data</strong>. For additional details on these configurations, view our <a href="./creating-a-deep-link.html">Deep Link Reference</a>.</p><p>The Branch Slack App will then output your Branch Link for you to send out.</p><p>.gif &quot;Create Link Details.gif&quot;)</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>To create links faster, you can supply the <code>/link</code> command with the following arguments:</p><ul><li><code>url</code>: The original web URL for your Branch Link. In cases where there isn&#39;t a mobile app page for your link, the users&#39; web browsers will open to this link.</li><li><code>alias</code>: Also known as a link slug, an alias will help your link be more readable and easy to find later on. If this is left blank, Branch will generate a unique link hash for you.</li></ul></div><h2 id="validate-your-link" tabindex="-1">Validate your link <a class="header-anchor" href="#validate-your-link" aria-label="Permalink to &quot;Validate your link&quot;">​</a></h2><p>If you would like to debug your link, you can use Branch&#39;s <a href="./link-debugger.html">Link Validator</a>. You can quickly access this by adding <code>?debug=1</code> at the end of your Branch Link. Here you can also edit your link.</p><p>.gif &quot;Link Debugger.gif&quot;)</p>',19)])])}const d=a(n,[["render",i]]);export{k as __pageData,d as default};
